    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen einem Interrupt und einem Polling-Mechanismus in Embedded Systems?", answerA = "Interrupts sind langsamer als Polling", answerB = "Polling prueft kontinuierlich einen Zustand, waehrend ein Interrupt die CPU asynchron signalisiert und sofort eine Handler-Routine ausfuehrt", answerC = "Interrupts werden nur in Echtzeitsystemen eingesetzt", answerD = "Polling ist energieeffizienter als Interrupts", correctAnswer = 1, explanation = "Polling belastet die CPU kontinuierlich. Interrupts erlauben der CPU, in einen Schlafmodus zu gehen und nur bei Ereignissen aufzuwachen - entscheidend fuer batteriebetriebene Embedded Devices.", difficulty = 3, funFact = "Moderne Mikrocontroller koennen im Stromspar-Modus auf unter 1 Mikroampere kommen und erst bei einem Interrupt wieder vollstaendig aufwachen."),
