    Question(categoryId = 7, questionText = "Was beschreibt der Begriff 'RTOS' (Real-Time Operating System) und welches Kernmerkmal unterscheidet es von einem normalen OS?", answerA = "Ein OS das nur auf ARM-Prozessoren laeuft", answerB = "Ein OS das deterministische Antwortzeiten (Worst-Case Execution Time) garantiert - Aufgaben muessen innerhalb fester Fristen abgeschlossen sein", answerC = "Ein OS mit besonders kurzer Bootzeit", answerD = "Ein Betriebssystem fuer eingebettete Linux-Systeme", correctAnswer = 1, explanation = "Ein RTOS garantiert Worst-Case Execution Time (WCET) fuer Tasks. Das ist in der Automobilelektronik, Luftfahrt und Medizintechnik essentiell, wo verspaetete Antworten lebensbedrohlich sein koennen.", difficulty = 3, funFact = "FreeRTOS, das meistgenutzte RTOS, wurde 2003 gegruendet und wird heute auf ueber 40 verschiedenen Prozessorarchitekturen eingesetzt."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen einem synchronen und einem asynchronen seriellen Bus (z.B. SPI vs UART)?", answerA = "Synchrone Busse sind langsamer als asynchrone", answerB = "Synchrone Busse nutzen eine gemeinsame Taktleitung zur Datensynchronisation, asynchrone Busse verwenden Start/Stop-Bits und eine vereinbarte Baudrate", answerC = "Asynchrone Busse benoetigen immer mehr Leitungen", answerD = "Synchrone Busse werden nur fuer Langstrecken eingesetzt", correctAnswer = 1, explanation = "SPI (synchron) uebertraegt den Takt mit, sodass beide Seiten exakt wissen wann Daten gueltig sind. UART (asynchron) vereinbart vorab eine Baudrate und rahmt Bytes mit Start/Stop-Bits ein.", difficulty = 3, funFact = "UART wurde 1960 erfunden und ist immer noch der Standard fuer Debug-Ausgaben in Embedded Systems - eine der bestaendigsten Schnittstellen in der Informatik."),
    Question(categoryId = 7, questionText = "Was ist Branch Prediction in einer modernen CPU und welche negative Konsequenz hat eine fehlerhafte Vorhersage?", answerA = "Ein Mechanismus zur Energieoptimierung bei Verzweigungen", answerB = "Eine Technik die spekulativ den wahrscheinlichsten Sprungpfad ausfuehrt; eine Fehlervorhersage erfordert das Verwerfen der Pipeline und kostet 10-20 Taktzyklen", answerC = "Ein Cache fuer Sprungtabellen im Betriebssystem", answerD = "Ein Compiler-Optimierungsschritt fuer bedingte Anweisungen", correctAnswer = 1, explanation = "Branch Predictors erreichen >95% Genauigkeit bei modernen CPUs. Eine Misprediction leert die Instruction Pipeline und verursacht einen Stall von typischerweise 10-20 Zyklen.", difficulty = 3, funFact = "Der Tournament Predictor in modernen Intel/AMD-CPUs kombiniert mehrere unabhaengige Prediktor-Algorithmen und waehlt dynamisch den zuverlaessigsten aus."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen dem DHCP-DORA-Prozess und einer statischen IP-Konfiguration in einem Netzwerk?", answerA = "DORA ist schneller als statische Konfiguration", answerB = "DORA (Discover/Offer/Request/Acknowledge) ist ein 4-Schritt-Handshake in dem ein DHCP-Server dynamisch eine IP-Adresse und Netzwerkparameter vergibt", answerC = "Statische IPs koennen nicht mit DHCP koexistieren", answerD = "DORA ist ein proprietaeres Cisco-Protokoll", correctAnswer = 1, explanation = "Im DORA-Ablauf sendet der Client zuerst ein Broadcast-Discover, empfaengt Angebote von DHCP-Servern, waehlt eines und bestaetigt die Zuweisung. Statische IPs werden manuell konfiguriert.", difficulty = 3, funFact = "DHCP Snooping ist ein Switch-Feature das gefaelschte DHCP-Server (Rogue DHCP) im Netzwerk blockiert."),
    Question(categoryId = 7, questionText = "Was ist OSPF und in welcher Routing-Kategorie ist es einzuordnen?", answerA = "Ein Distanzvektor-Protokoll das Hop-Count nutzt", answerB = "Ein Link-State-Interior-Gateway-Protokoll das den Dijkstra-Algorithmus auf einer vollstaendigen Netztopologie-Karte anwendet", answerC = "Ein externes BGP-Routing-Protokoll fuer das Internet", answerD = "Ein proprietaeres Cisco-Routing-Protokoll", correctAnswer = 1, explanation = "OSPF (Open Shortest Path First) ist ein Link-State-Protokoll: Jeder Router fluted seine Verbindungsinformationen (LSAs) und berechnet dann lokal mit dem Dijkstra-Algorithmus den kuerzesten Pfad.", difficulty = 3, funFact = "OSPF nutzt Multicast-Adressen 224.0.0.5 und 224.0.0.6 fuer effiziente Kommunikation und vermeidet so unnoetige Broadcasts."),
    Question(categoryId = 7, questionText = "Welche Eigenschaft zeichnet eine CRC (Cyclic Redundancy Check) gegenueber einer einfachen Pruefsumme aus?", answerA = "CRC ist schneller zu berechnen", answerB = "CRC basiert auf Polynomteilung und kann Burst-Fehler (mehrere aufeinanderfolgende fehlerhafte Bits) zuverlaessig erkennen", answerC = "CRC kann Fehler automatisch korrigieren", answerD = "CRC wird nur in Datenbanken eingesetzt", correctAnswer = 1, explanation = "CRC teilt die Datenbits als Polynom durch ein Generatorpolynom. Das Ergebnis (Rest) ist extrem sensitiv gegenueber Burst-Fehlern, die bei einer einfachen Summe oft unerkannt bleiben.", difficulty = 3, funFact = "CRC-32 (IEEE 802.3) wird in Ethernet, ZIP, PNG und vielen anderen Formaten verwendet und kann alle Burst-Fehler bis 32 Bit und fast alle laengeren Fehler erkennen."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen symmetrischer (AES) und asymmetrischer Verschluesselung (RSA) bezueglich des Schluesseltauschs?", answerA = "AES-Schluessel koennen oeffentlich ausgetauscht werden, RSA-Schluessel nicht", answerB = "AES benoetigt einen gemeinsamen geheimen Schluessel (Key Distribution Problem), RSA loest dies durch ein oeffentliches/privates Schluesselpaar", answerC = "RSA ist schneller als AES bei der Datenverschluesselung", answerD = "Beide Verfahren nutzen denselben Schluesseltausch-Mechanismus", correctAnswer = 1, explanation = "Das klassische Problem symmetrischer Kryptographie ist: wie tauscht man den geheimen Schluessel sicher aus? RSA loest dies mit mathematisch verbundenen Schluesseln - was mit einem verschluesselt wird, kann nur der andere entschluesseln.", difficulty = 3, funFact = "In der Praxis wird meist Hybrid-Kryptographie eingesetzt: RSA tauscht einen AES-Sitzungsschluessel aus, dann verschluesselt das schnelle AES die eigentlichen Daten."),
    Question(categoryId = 7, questionText = "Was ist das CAP-Theorem in verteilten Systemen?", answerA = "Ein Theorem ueber CPU-Cache-Aufteilung", answerB = "Consistency, Availability und Partition Tolerance koennen in einem verteilten System nicht alle drei gleichzeitig garantiert werden", answerC = "Ein Optimierungstheorem fuer Datenbanken", answerD = "Ein Modell zur Berechnung von Netzwerklatenz", correctAnswer = 1, explanation = "Das CAP-Theorem (Brewer 2000) besagt: Bei einer Netzwerkpartitionierung (P) muss ein System zwischen starker Konsistenz (C) und hoher Verfuegbarkeit (A) waehlen. CP-Systeme: HBase. AP-Systeme: Cassandra.", difficulty = 3, funFact = "Eric Brewer stellte die CAP-Hypothese 2000 vor, 2002 wurde sie formell von Gilbert und Lynch bewiesen. Das PACELC-Modell verfeinert CAP um Latenz-Aspekte."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen einem JTAG-Interface und einem SWD-Interface in der Embedded-Entwicklung?", answerA = "JTAG ist neuer als SWD", answerB = "JTAG nutzt 4-5 Leitungen fuer Test und Debug, SWD (Serial Wire Debug) ist ein ARM-spezifisches 2-Leitungs-Interface das kompatibler Funktionsumfang bei weniger Pins bietet", answerC = "SWD kann keine Breakpoints setzen", answerD = "JTAG ist nur fuer FPGAs geeignet", correctAnswer = 1, explanation = "JTAG (IEEE 1149.1) wurde 1990 fuer Boundary-Scan-Tests entworfen und wird fuer FPGAs, Prozessoren und PCB-Test eingesetzt. SWD ist eine ARM-Vereinfachung mit nur SWDIO und SWDCLK.", difficulty = 3, funFact = "SWD wurde mit ARM Cortex-M eingefuehrt und ist heute der Standard-Debug-Anschluss auf Entwicklungsboards wie dem STM32 Nucleo."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen einem Microcontroller und einem Mikroprozessor?", answerA = "Mikroprozessoren sind kleiner als Microcontroller", answerB = "Ein Microcontroller integriert CPU, RAM, Flash, Timer und Peripherie auf einem Chip. Ein Mikroprozessor ist nur die CPU und benoetigt externe Komponenten", answerC = "Microcontroller laufen immer mit weniger als 1 MHz Takt", answerD = "Mikroprozessoren koennen keinen Code ausfuehren", correctAnswer = 1, explanation = "MCUs wie der STM32 oder Arduino-Prozessor haben alles auf einem Chip: CPU, Speicher, GPIO, ADC, Kommunikationsperipherie. Mikroprozessoren wie Intel Core brauchen externes RAM, Chipsatz, etc.", difficulty = 3, funFact = "Intel 4004 (1971) war der erste kommerzielle Mikroprozessor. Der erste erfolgreiche Microcontroller war der Intel 8048 (1976), der in Millionen von PC-Tastaturen eingebaut wurde."),
    Question(categoryId = 7, questionText = "Was ist DMA (Direct Memory Access) und welchen Vorteil bietet es gegenueber CPU-gesteuertem Datentransfer?", answerA = "DMA ist ein Cache-Mechanismus fuer haufig gelesene Speicherbereiche", answerB = "DMA erlaubt Peripheriegeraeten, direkt Daten zwischen Speicher und Geraet zu transportieren ohne CPU-Beteiligung, was die CPU fuer andere Aufgaben freigibt", answerC = "DMA verdoppelt die Speicherbandbreite durch parallele Zugriffskanale", answerD = "DMA ist ein Verschluesselungsmodul fuer Speicher", correctAnswer = 1, explanation = "Ohne DMA muss die CPU jeden Byte-Transfer zwischen Peripherie und RAM ueber Register abwickeln. DMA-Controller uebernehmen dies selbststaendig und signalisieren der CPU per Interrupt wenn der Transfer abgeschlossen ist.", difficulty = 3, funFact = "DMA wurde 1964 im IBM System/360 eingefuehrt. Modernes USB3 und PCIe nutzen aehnliche Prinzipien (IOMMU) um direkten Speicherzugriff sicher zu gestalten."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen RISC und CISC-Prozessorarchitekturen?", answerA = "RISC-Prozessoren sind immer schneller als CISC", answerB = "RISC hat wenige einfache Befehle die in einem Taktzyklus ausfuehren, CISC hat komplexe Befehle die mehrere Zyklen und Mikro-Ops benoetigen", answerC = "CISC ist nur fuer Server geeignet", answerD = "RISC-Prozessoren benoetigen mehr Transistoren als CISC", correctAnswer = 1, explanation = "RISC (ARM, RISC-V) vereinfacht die Hardware und verlagert Komplexitaet in den Compiler. x86 (CISC) uebersetzte komplexe Makro-Befehle intern in Micro-Ops - damit sind moderne x86-CPUs intern RISC-aehnlich.", difficulty = 3, funFact = "Der Apple M1 zeigte 2020 eindrucksvoll, dass RISC (ARM) auch bei High-Performance-Computing mit CISC (x86) mithalten und es oft uebertreffen kann."),
    Question(categoryId = 7, questionText = "Was ist ein Phase-Locked Loop (PLL) und wofuer wird er in elektronischen Systemen eingesetzt?", answerA = "Ein analoges Filter zur Rauschunterdrueckung", answerB = "Eine rueckgekoppelte Schaltung die die Phase eines Ausgangssignals an ein Referenzsignal angleicht, genutzt zur Frequenzmultiplikation und Taktgenerierung", answerC = "Ein digitaler Verstaerker fuer Hochfrequenzsignale", answerD = "Ein Speichermodul fuer Taktfrequenzen", correctAnswer = 1, explanation = "Ein PLL besteht aus Phasendetektor, Schleifenfilter und VCO (Voltage Controlled Oscillator). Er multipliziert Referenztakte (z.B. 25 MHz Quarz → 3 GHz CPU-Takt) und filtert Jitter.", difficulty = 3, funFact = "Jeder Prozessor, FPGA und RF-Chip enthaelt mehrere PLLs. Ohne sie waere modernes Hochgeschwindigkeits-Computing unmoeglich."),
    Question(categoryId = 7, questionText = "Was beschreibt das Konzept der 'Rowhammer'-Attacke in DRAM-Systemen?", answerA = "Ein physischer Angriff durch elektromagnetische Felder von aussen", answerB = "Das wiederholte Aktivieren benachbarter DRAM-Zeilen um durch Kapazitaetskopplung Bit-Flips in einer Zielzeile zu induzieren", answerC = "Ein Fehler im DRAM-Refresh-Algorithmus des Betriebssystems", answerD = "Ein Buffer-Overflow-Angriff auf DRAM-Controller-Treiber", correctAnswer = 1, explanation = "Rowhammer nutzt physikalische DRAM-Eigenschaften: Durch schnelles, wiederholtes Zugreifen auf benachbarte Zeilen ladet sich eine Zeile durch Kopplung um und kann Bit-Flips erzeugen - genug um Privilegien zu eskalieren.", difficulty = 3, funFact = "Google Project Zero demonstrierte 2015 einen Rowhammer-Angriff der JavaScript-Code im Browser nutzte um Kernel-Privilegien zu erlangen, ohne jede klassische Softwareverarbeitbarkeit."),
    Question(categoryId = 7, questionText = "Welche Bitrate erreicht 100GBase-SR4 Ethernet und ueber welches Medium?", answerA = "100 Gbit/s ueber Kupferkabel bis 100 Meter", answerB = "100 Gbit/s ueber 4 Multimode-Glasfaserpaare (OM3/OM4) bis zu 100 Meter", answerC = "100 Gbit/s ueber Singlemode-Glasfaser bis 40 Kilometer", answerD = "100 Gbit/s ueber koaxiales Kupferkabel", correctAnswer = 1, explanation = "100GBase-SR4 nutzt 4 Lanes zu je 25 Gbit/s auf Multimode-Glasfaser (850 nm). OM3 erlaubt 70 m, OM4 bis 100 m Reichweite.", difficulty = 3, funFact = "Rechenzentren nutzen 'Breakout-Kabel' die ein 100G-QSFP28 in vier 25G-SFP28-Verbindungen aufteilen, um Blattschalter flexibel anzubinden."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen Hamming-Code und Reed-Solomon-Code bei der Fehlerkorrektur?", answerA = "Hamming-Code ist fuer Burst-Fehler, Reed-Solomon fuer Einzelbit-Fehler optimiert", answerB = "Hamming-Code korrigiert Einzelbit-Fehler in binaeren Daten, Reed-Solomon korrigiert Fehler in ganzen Symbolen (Byte-Bloecken) und ist ideal fuer Burst-Fehler", answerC = "Reed-Solomon benoetigt weniger Redundanz als Hamming", answerD = "Beide Codes sind identisch in ihrer Fehlerkorrekturkapazitaet", correctAnswer = 1, explanation = "Hamming-Code addiert Parity-Bits um genau ein umgekipptes Bit zu identifizieren und korrigieren. Reed-Solomon arbeitet auf Galois-Feld-Polynomen und korrigiert ganze fehlerhafte Byte-Pakete - perfekt fuer CDs/DVDs, RAID, QR-Codes.", difficulty = 3, funFact = "Reed-Solomon wird in QR-Codes verwendet und kann bis zu 30% eines beschaedigten Codes rekonstruieren - deshalb lassen sich QR-Codes mit Logo-Ueberlagerungen noch lesen."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen einem Prozess und einem Thread im Betriebssystem-Kontext?", answerA = "Threads sind Prozesse mit weniger Speicher", answerB = "Prozesse haben eigene Adressraeume und Ressourcen, Threads teilen sich den Adressraum eines Prozesses und kommunizieren ueber gemeinsamen Speicher", answerC = "Prozesse koennen nicht parallel laufen, Threads schon", answerD = "Threads sind nur in UNIX-Systemen verfuegbar", correctAnswer = 1, explanation = "Ein Prozess ist eine Isolationseinheit mit eigenem Speicher, Dateideskriptoren und Sicherheitskontext. Threads innerhalb eines Prozesses teilen sich Heap und globale Variablen, haben aber eigene Stacks und CPU-Register.", difficulty = 3, funFact = "Context-Switch zwischen Threads desselben Prozesses ist ca. 5-10x schneller als zwischen Prozessen, da kein Adressraum-Wechsel (TLB-Flush) noetig ist."),
    Question(categoryId = 7, questionText = "Was ist das Amdahlsche Gesetz und welche Grenze setzt es der parallelen Beschleunigung?", answerA = "Ein Gesetz ueber die maximale Taktfrequenz von CPUs", answerB = "Speedup = 1 / (S + (1-S)/N) — der serielle Anteil S eines Programms begrenzt die maximale Beschleunigung unabhaengig von der Anzahl N der Prozessoren", answerC = "Ein Gesetz ueber den optimalen Cache-Groesse fuer parallele Algorithmen", answerD = "Die Regel dass parallele Programme immer schneller als serielle sind", correctAnswer = 1, explanation = "Wenn 10% eines Programms seriell ist, kann man es maximal 10x beschleunigen, egal wie viele Kerne man hinzufuegt. Das Gesetz erklaert warum Parallelisierung schnell an Grenzen stosst.", difficulty = 3, funFact = "Gene Amdahl formulierte das Gesetz 1967 als Argument gegen Massiv-Parallelrechner. Gustafson erweiterte es 1988: Bei wachsenden Problemen skaliert Parallelisierung besser."),
    Question(categoryId = 7, questionText = "Was ist ein ASIC und worin unterscheidet er sich von einem FPGA?", answerA = "ASICs sind guenstiger in der Entwicklung als FPGAs", answerB = "Ein ASIC ist ein anwendungsspezifischer Schaltkreis der fest verdrahtet ist und nicht umprogrammiert werden kann, waehrend ein FPGA rekonfigurierbar bleibt", answerC = "FPGAs koennen keine digitalen Signale verarbeiten", answerD = "ASICs werden nur in der Luft- und Raumfahrt eingesetzt", correctAnswer = 1, explanation = "ASICs werden fuer einen spezifischen Zweck hergestellt (z.B. Bitcoin-Mining-Chips, iPhone-Neural-Engine) und sind 10-100x schneller und energieeffizienter als ein FPGA fuer dieselbe Funktion. Ein FPGA kann dagegen fuer jede Aufgabe umprogrammiert werden.", difficulty = 3, funFact = "Ein moderner 7-nm ASIC-Entwicklungsprozess kostet 30-100 Millionen Euro an Designgebuhren, weshalb nur Massenfertigung sich rentiert."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen littler Endian und Big Endian bei der Bytespeicherung?", answerA = "Little Endian ist moderner und effizienter als Big Endian", answerB = "Little Endian speichert das niederwertigste Byte zuerst (an niedrigster Adresse), Big Endian das hoeherwertigste Byte zuerst", answerC = "Big Endian wird nur in ARM-Prozessoren verwendet", answerD = "Beide Formate sind bei modernen CPUs identisch", correctAnswer = 1, explanation = "Bei Little Endian (x86, ARM LE) steht das LSB an der niedrigsten Adresse. Bei Big Endian (Netzwerkprotokolle, MIPS, PowerPC BE) steht das MSB zuerst. Netzwerkkommunikation nutzt 'Network Byte Order' = Big Endian.", difficulty = 3, funFact = "Der Begriff stammt aus Jonathan Swifts 'Gullivers Reisen': Die Liliputaner fuehren Krieg darueber, von welchem Ende man ein Ei aufschlagen soll."),
    Question(categoryId = 7, questionText = "Was ist die Funktion eines DDR5-DRAM-Training-Algorithmus beim Systemstart?", answerA = "Das Herunterladen von BIOS-Updates", answerB = "Das automatische Kalibrieren von Signaltiming, Leitungsverzoegerungen und Strom-Biases zwischen Speichercontroller und DIMM-Modulen", answerC = "Das Aufwaermen der Speichermodule auf Betriebstemperatur", answerD = "Das Ueberpruefen der Speicherkapazitaet durch UEFI", correctAnswer = 1, explanation = "DRAM-Training kompensiert Leitungslaufzeiten, Crosstalk und individuelle Silizium-Varianzen. Ohne Training wuerden Schreibbefehle am falschen Bit-Sampling-Zeitpunkt eingetastet.", difficulty = 3, funFact = "DDR5-Training kann 30-60 Sekunden beim Kaltstart dauern. Deshalb reagiert ein frisch aufgeweckter PC manchmal nach einem BIOS-Update so lange nicht."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen einem NAND-Gate und einem NOR-Gate hinsichtlich ihrer Vollstaendigkeit?", answerA = "Nur NOR-Gatter sind funktional vollstaendig", answerB = "Beide sind fuer sich allein funktional vollstaendig (Sheffer Stroke): Jede Boolesche Funktion laesst sich ausschliesslich aus NAND-Gattern oder ausschliesslich aus NOR-Gattern aufbauen", answerC = "Weder NAND noch NOR sind funktional vollstaendig", answerD = "Nur NAND-Gatter werden in realen Schaltkreisen eingesetzt", correctAnswer = 1, explanation = "NAND- und NOR-Gatter sind die einzigen universellen Gatter. NOT(A) = A NAND A, AND(A,B) = NOT(A NAND B), OR(A,B) = (NOT A) NAND (NOT B). Dasselbe gilt analog fuer NOR.", difficulty = 3, funFact = "CMOS-Technologie bevorzugt NAND-Gatter, da sie in CMOS einfacher und flaecheneffizienter als NOR zu implementieren sind."),
    Question(categoryId = 7, questionText = "Was ist IEEE 754 und welche Probleme loest es in der Gleitkommaarithmetik?", answerA = "Ein Standard fuer Netzwerkprotokolle", answerB = "Ein Standard fuer binaere Gleitkommadarstellung (Sign, Exponent, Mantisse) der Sonderwerte wie Inf, NaN und Denormals definiert und Portabilitaet zwischen Systemen sicherstellt", answerC = "Ein Kompressionsformat fuer wissenschaftliche Berechnungen", answerD = "Ein Verschluesselungsstandard fuer Finanzdaten", correctAnswer = 1, explanation = "IEEE 754 (1985) definiert Single (32 Bit) und Double (64 Bit) Precision Floating Point. Ohne den Standard lieferten Programme auf verschiedenen Computern unterschiedliche Ergebnisse.", difficulty = 3, funFact = "0.1 + 0.2 != 0.3 in Gleitkomma ist eine direkte Folge von IEEE 754: 0.1 ist in binaer eine Periode mit unendlich vielen Stellen, die auf 53 Bit abgeschnitten wird."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen Latenz und Bandbreite in Computersystemen?", answerA = "Latenz beschreibt die Datenmenge pro Sekunde, Bandbreite die Verzoegerung", answerB = "Latenz ist die Zeit von Anfrage bis zur ersten Antwort, Bandbreite ist die maximale Datenmenge pro Zeiteinheit", answerC = "Beide Begriffe sind synonym in der Netzwerktechnik", answerD = "Bandbreite ist nur fuer drahtlose Netzwerke relevant", correctAnswer = 1, explanation = "Latenz = Zeit bis erstes Byte ankommt (z.B. 1 ms NVMe, 100 ms HDD). Bandbreite = Durchsatz (GB/s). Hohe Bandbreite bei hoher Latenz ist wie eine grosse aber langsame Rohrleitung.", difficulty = 3, funFact = "Transatlantische Glasfaserkabel haben 70 ms Latenz (physikalische Untergrenze: Lichtgeschwindigkeit) aber Terabit/s Bandbreite — der fundamentale Unterschied zwischen Groesse und Geschwindigkeit."),
    Question(categoryId = 7, questionText = "Was ist NUMA (Non-Uniform Memory Access) und welche Auswirkung hat es auf die Programmierung von Server-Software?", answerA = "Ein Speicherzugriffsprotokoll fuer Embedded Systems", answerB = "Eine Architektur bei der CPUs auf ihren lokalen RAM schneller zugreifen als auf RAM anderer CPUs; falsche NUMA-Affinitaet kann Leistung um 30-50% reduzieren", answerC = "Ein Virtualisierungsfeature fuer Speicher-Overcommit", answerD = "Ein Cache-Kohaerenzmechanismus fuer Multi-Core-CPUs", correctAnswer = 1, explanation = "In NUMA-Systemen (Multi-Sockel-Server) hat jede CPU ihren 'nahen' RAM. Zugriff auf 'entfernten' RAM eines anderen Sockets kostet extra Latenz. Betriebssystem-Scheduler und NUMA-aware Anwendungen muessen Thread und Speicher auf demselben Node halten.", difficulty = 3, funFact = "Linux nutzt numactl und dem NUMA-Scheduler um Prozesse an NUMA-Nodes zu binden. Falsche NUMA-Placement ist ein haeufiger Grund fuer unerklraerliche Leistungseinbrueche auf Servern.")
)
